[asy]
import TrigMacros; 
size(180); 

pair O, A, B, C;

rr_cartesian_axes(-2, 8, -5, 7, complexplane = true, usegrid = false); 
O = (0,0); 
A = (3, -1); 
B = scale(sqrt(2))*rotate(45)*A; 
C = rotate(90)*A; 

draw(A--B--C--O--cycle); 
draw(O--B); 

dot("$a$", A, S); 
dot("$b$", B, E); 
dot("$c$", C, N); 
dot("$0$", O, SW); 
